  1→/**
  2→ * ProductionRepository - CRUD operations for Production model
  3→ *
  4→ * Provides typed methods for Production queries with soft-delete support.
  5→ * Handles Production stage transitions with proper cascade behavior.
  6→ */
  7→
  8→import { prisma } from './prisma';
  9→import type {
 10→  Production,
 11→  ProductionStage,
 12→  Prisma,
 13→} from '@prisma/client';
 14→import { randomUUID } from 'node:crypto';
 15→
 16→/**
 17→ * Production creation input type
 18→ */
 19→export type ProductionCreateInput = Omit<Prisma.ProductionUncheckedCreateInput, 'id' | 'updatedAt'> & Partial<Pick<Prisma.ProductionUncheckedCreateInput, 'id' | 'updatedAt'>>;
 20→
 21→/**
 22→ * Production update input type
 23→ */
 24→export type ProductionUpdateInput = Prisma.ProductionUncheckedUpdateInput;
 25→
 26→/**
 27→ * Production findMany params type
 28→ */
 29→export type ProductionFindManyParams = {
 30→  where?: Prisma.ProductionWhereInput;
 31→  orderBy?: Prisma.ProductionOrderByWithRelationInput;
 32→  skip?: number;
 33→  take?: number;
 34→  include?: Prisma.ProductionInclude;
 35→};
 36→
 37→/**
 38→ * ProductionStage creation input type
 39→ */
 40→export type ProductionStageCreateInput = Omit<Prisma.ProductionStageUncheckedCreateInput, 'id' | 'updatedAt'> & Partial<Pick<Prisma.ProductionStageUncheckedCreateInput, 'id' | 'updatedAt'>>;
 41→
 42→/**
 43→ * ProductionStage update input type
 44→ */
 45→export type ProductionStageUpdateInput = Prisma.ProductionStageUncheckedUpdateInput;
 46→
 47→/**
 48→ * Repository for Production CRUD operations
 49→ */
 50→export class ProductionRepository {
 51→  /**
 52→   * Find many productions with optional filtering
 53→   * Automatically filters out soft-deleted records
 54→   */
 55→  async findMany(params?: ProductionFindManyParams): Promise<Production[]> {
 56→    const { where, ...rest } = params ?? {};
 57→
 58→    return prisma.production.findMany({
 59→      ...rest,
 60→      where: {
 61→        ...where,
 62→        deletedAt: null, // Always exclude soft-deleted
 63→      },
 64→    });
 65→  }
 66→
 67→  /**
 68→   * Find a single production by ID
 69→   * Returns null if not found or soft-deleted
 70→   */
 71→  async findUnique(
 72→    id: string,
 73→    include?: Prisma.ProductionInclude
 74→  ): Promise<Production | null> {
 75→    return prisma.production.findFirst({
 76→      where: { id, deletedAt: null },
 77→      include,
 78→    });
 79→  }
 80→
 81→  /**
 82→   * Find productions by project ID
 83→   */
 84→  async findByProject(projectId: string): Promise<Production[]> {
 85→    return this.findMany({
 86→      where: { projectId },
 87→      orderBy: { createdAt: 'desc' },
 88→    });
 89→  }
 90→
 91→  /**
 92→   * Find productions by status
 93→   */
 94→  async findByStatus(status: string): Promise<Production[]> {
 95→    return this.findMany({
 96→      where: { status },
 97→      orderBy: { createdAt: 'desc' },
 98→    });
 99→  }
100→
101→  /**
102→   * Create a new production
103→   * Generates UUID and timestamps if not provided
104→   */
105→  async create(data: ProductionCreateInput): Promise<Production> {
106→    const now = new Date();
107→
108→    return prisma.production.create({
109→      data: {
110→        ...data,
111→        id: data.id ?? randomUUID(),
112→        createdAt: data.createdAt ?? now,
113→        updatedAt: data.updatedAt ?? now,
114→      },
115→    });
116→  }
117→
118→  /**
119→   * Update an existing production
120→   * Throws RecordNotFound if production doesn't exist or is soft-deleted
121→   */
122→  async update(
123→    id: string,
124→    data: ProductionUpdateInput
125→  ): Promise<Production> {
126→    // Verify production exists and not deleted
127→    const existing = await this.findUnique(id);
128→    if (!existing) {
129→      throw new Error(`Production with id ${id} not found`);
130→    }
131→
132→    return prisma.production.update({
133→      where: { id },
134→      data: {
135→        ...data,
136→        updatedAt: new Date(),
137→      },
138→    });
139→  }
140→
141→  /**
142→   * Soft delete a production by setting deletedAt timestamp
143→   * Does NOT actually delete the record from database
144→   */
145→  async softDelete(id: string): Promise<Production> {
146→    // Verify production exists and not already deleted
147→    const existing = await this.findUnique(id);
148→    if (!existing) {
149→      throw new Error(`Production with id ${id} not found`);
150→    }
151→
152→    return prisma.production.update({
153→      where: { id },
154→      data: { deletedAt: new Date() },
155→    });
156→  }
157→
158→  /**
159→   * Count productions matching criteria (excluding soft-deleted)
160→   */
161→  async count(where?: Prisma.ProductionWhereInput): Promise<number> {
162→    return prisma.production.count({
163→      where: {
164→        ...where,
165→        deletedAt: null,
166→      },
167→    });
168→  }
169→
170→  /**
171→   * Update production progress
172→   */
173→  async updateProgress(id: string, progress: number): Promise<Production> {
174→    if (progress < 0 || progress > 100) {
175→      throw new Error('Progress must be between 0 and 100');
176→    }
177→
178→    return this.update(id, { progress });
179→  }
180→
181→  /**
182→   * Start production - sets status to 'active' and actualStartDate
183→   */
184→  async start(id: string): Promise<Production> {
185→    const now = new Date();
186→    return this.update(id, {
187→      status: 'active',
188→      actualStartDate: now,
189→    });
190→  }
191→
192→  /**
193→   * Complete production - sets status to 'completed', progress to 100, and actualEndDate
194→   */
195→  async complete(id: string): Promise<Production> {
196→    const now = new Date();
197→    return this.update(id, {
198→      status: 'completed',
199→      progress: 100,
200→      actualEndDate: now,
201→    });
202→  }
203→
204→  /**
205→   * Move production to a different status
206→   */
207→  async moveStatus(
208→    id: string,
209→    status: string
210→  ): Promise<Production> {
211→    return this.update(id, { status });
212→  }
213→
214→  // ==================== ProductionStage methods ====================
215→
216→  /**
217→   * Find production stages for a production
218→   */
219→  async findStages(productionId: string): Promise<ProductionStage[]> {
220→    return prisma.productionStage.findMany({
221→      where: { productionId },
222→      orderBy: { order: 'asc' },
223→    });
224→  }
225→
226→  /**
227→   * Find a single production stage by ID
228→   */
229→  async findStage(id: string): Promise<ProductionStage | null> {
230→    return prisma.productionStage.findUnique({
231→      where: { id },
232→    });
233→  }
234→
235→  /**
236→   * Find production stages by status
237→   */
238→  async findStagesByStatus(productionId: string, status: string): Promise<ProductionStage[]> {
239→    return prisma.productionStage.findMany({
240→      where: { productionId, status },
241→      orderBy: { order: 'asc' },
242→    });
243→  }
244→
245→  /**
246→   * Create a new production stage
247→   */
248→  async createStage(data: ProductionStageCreateInput): Promise<ProductionStage> {
249→    const now = new Date();
250→
251→    return prisma.productionStage.create({
252→      data: {
253→        ...data,
254→        id: data.id ?? randomUUID(),
255→        createdAt: data.createdAt ?? now,
256→        updatedAt: data.updatedAt ?? now,
257→      },
258→    });
259→  }
260→
261→  /**
262→   * Update an existing production stage
263→   */
264→  async updateStage(
265→    id: string,
266→    data: ProductionStageUpdateInput
267→  ): Promise<ProductionStage> {
268→    // Verify stage exists
269→    const existing = await this.findStage(id);
270→    if (!existing) {
271→      throw new Error(`ProductionStage with id ${id} not found`);
272→    }
273→
274→    return prisma.productionStage.update({
275→      where: { id },
276→      data: {
277→        ...data,
278→        updatedAt: new Date(),
279→      },
280→    });
281→  }
282→
283→  /**
284→   * Move a production stage to a different status
285→   * Automatically sets completedAt when moving to completed status
286→   */
287→  async moveStage(
288→    stageId: string,
289→    status: string,
290→    completedAt?: Date
291→  ): Promise<ProductionStage> {
292→    const stage = await this.findStage(stageId);
293→    if (!stage) {
294→      throw new Error(`ProductionStage with id ${stageId} not found`);
295→    }
296→
297→    const updateData: Prisma.ProductionStageUpdateInput = {
298→      status,
299→      updatedAt: new Date(),
300→    };
301→
302→    // Set completedAt if status is 'completed' or provided
303→    if (status === 'completed' || completedAt) {
304→      updateData.completedAt = completedAt ?? new Date();
305→    }
306→
307→    return prisma.productionStage.update({
308→      where: { id: stageId },
309→      data: updateData,
310→    });
311→  }
312→
313→  /**
314→   * Delete a production stage
315→   * This is a hard delete since stages have no soft-delete
316→   */
317→  async deleteStage(id: string): Promise<ProductionStage> {
318→    const stage = await this.findStage(id);
319→    if (!stage) {
320→      throw new Error(`ProductionStage with id ${id} not found`);
321→    }
322→
323→    return prisma.productionStage.delete({
324→      where: { id },
325→    });
